1	/**
2	 * The Oculus — web dashboard apparatus.
3	 *
4	 * Serves a web dashboard via Hono. Plugins contribute pages as static asset
5	 * directories and custom API routes through kit contributions. Guild tools are
6	 * automatically exposed as REST endpoints.
7	 */
8	
9	import fs from 'node:fs';
10	import path from 'node:path';
11	import { Hono } from 'hono';
12	import { serve } from '@hono/node-server';
13	import type { Server } from 'node:http';
14	import { z } from 'zod';
15	
16	import type { Plugin, StartupContext, LoadedKit, LoadedApparatus } from '@shardworks/nexus-core';
17	import { guild } from '@shardworks/nexus-core';
18	import type { InstrumentariumApi } from '@shardworks/tools-apparatus';
19	import { tool } from '@shardworks/tools-apparatus';
20	
21	import type { OculusApi, OculusConfig, OculusKit, PageContribution, RouteContribution } from './types.ts';
22	
23	// ── MIME types ────────────────────────────────────────────────────────
24	
25	const MIME_TYPES: Record<string, string> = {
26	  '.html': 'text/html; charset=utf-8',
27	  '.css': 'text/css; charset=utf-8',
28	  '.js': 'application/javascript; charset=utf-8',
29	  '.mjs': 'application/javascript; charset=utf-8',
30	  '.json': 'application/json; charset=utf-8',
31	  '.png': 'image/png',
32	  '.jpg': 'image/jpeg',
33	  '.jpeg': 'image/jpeg',
34	  '.gif': 'image/gif',
35	  '.svg': 'image/svg+xml',
36	  '.ico': 'image/x-icon',
37	  '.woff': 'font/woff',
38	  '.woff2': 'font/woff2',
39	  '.ttf': 'font/ttf',
40	  '.map': 'application/json',
41	};
42	
43	function getMimeType(filePath: string): string {
44	  const ext = path.extname(filePath).toLowerCase();
45	  return MIME_TYPES[ext] ?? 'application/octet-stream';
46	}
47	
48	// ── Tool→REST mapping helpers ─────────────────────────────────────────
49	
50	export function toolNameToRoute(name: string): string {
51	  const idx = name.indexOf('-');
52	  if (idx === -1) return `/api/${name}`;
53	  return `/api/${name.slice(0, idx)}/${name.slice(idx + 1)}`;
54	}
55	
56	export function permissionToMethod(permission: string | undefined): 'GET' | 'POST' | 'DELETE' {
57	  if (permission === undefined) return 'GET';
58	  const level = permission.includes(':')
59	    ? permission.slice(permission.lastIndexOf(':') + 1)
60	    : permission;
61	  if (level === 'read') return 'GET';
62	  if (level === 'write' || level === 'admin') return 'POST';
63	  if (level === 'delete') return 'DELETE';
64	  return 'POST';
65	}
66	
67	// ── Query param coercion ──────────────────────────────────────────────
68	
69	function isNumberSchema(schema: z.ZodTypeAny): boolean {
70	  let inner: z.ZodTypeAny = schema;
71	  if (inner instanceof z.ZodOptional) inner = inner.unwrap() as z.ZodTypeAny;
72	  if (inner instanceof z.ZodDefault) inner = inner.unwrap() as z.ZodTypeAny;
73	  if (inner instanceof z.ZodOptional) inner = inner.unwrap() as z.ZodTypeAny;
74	  return inner instanceof z.ZodNumber;
75	}
76	
77	function isBooleanSchema(schema: z.ZodTypeAny): boolean {
78	  let inner: z.ZodTypeAny = schema;
79	  if (inner instanceof z.ZodOptional) inner = inner.unwrap() as z.ZodTypeAny;
80	  if (inner instanceof z.ZodDefault) inner = inner.unwrap() as z.ZodTypeAny;
81	  if (inner instanceof z.ZodOptional) inner = inner.unwrap() as z.ZodTypeAny;
82	  return inner instanceof z.ZodBoolean;
83	}
84	
85	export function coerceParams(
86	  shape: Record<string, z.ZodTypeAny>,
87	  params: Record<string, string>,
88	): Record<string, unknown> {
89	  const result: Record<string, unknown> = { ...params };
90	  for (const [key, schema] of Object.entries(shape)) {
91	    const value = result[key];
92	    if (typeof value !== 'string') continue;
93	    if (isNumberSchema(schema)) {
94	      result[key] = Number(value);
95	    } else if (isBooleanSchema(schema)) {
96	      result[key] = value === 'true';
97	    }
98	  }
99	  return result;
100	}
101	
102	// ── Chrome injection ─────────────────────────────────────────────────
103	
104	export function injectChrome(html: string, stylesheetPath: string, navHtml: string): string {
105	  // Check for </head> case-insensitively
106	  const headCloseMatch = html.match(/<\/head>/i);
107	  const bodyOpenMatch = html.match(/<body[^>]*>/i);
108	
109	  // If neither tag present, return unmodified
110	  if (!headCloseMatch && !bodyOpenMatch) return html;
111	
112	  let result = html;
113	
114	  // Insert stylesheet link before </head>
115	  if (headCloseMatch && headCloseMatch.index !== undefined) {
116	    const idx = headCloseMatch.index;
117	    result =
118	      result.slice(0, idx) +
119	      `<link rel="stylesheet" href="${stylesheetPath}">` +
120	      result.slice(idx);
121	  }
122	
123	  // Insert nav after <body...>
124	  // Need to recalculate position after potential head insertion
125	  const bodyMatch = result.match(/<body[^>]*>/i);
126	  if (bodyMatch && bodyMatch.index !== undefined) {
127	    const idx = bodyMatch.index + bodyMatch[0].length;
128	    result = result.slice(0, idx) + navHtml + result.slice(idx);
129	  }
130	
131	  return result;
132	}
133	
134	function buildNavHtml(pages: PageContribution[]): string {
135	  const pageLinks = pages
136	    .map((p) => `<a href="/pages/${p.id}/">${p.title}</a>`)
137	    .join('\n  ');
138	  return `<nav id="oculus-nav">
139	  <a href="/">Guild</a>
140	  ${pageLinks}
141	</nav>`;
142	}
143	
144	// ── Tool param extraction (reimplemented from tools-show) ────────────
145	
146	interface ParamInfo {
147	  type: string;
148	  description: string | null;
149	  optional: boolean;
150	}
151	
152	function zodTypeToJsonType(zodType: z.ZodType): string {
153	  if (zodType instanceof z.ZodString) return 'string';
154	  if (zodType instanceof z.ZodNumber) return 'number';
155	  if (zodType instanceof z.ZodBoolean) return 'boolean';
156	  if (zodType instanceof z.ZodArray) return 'array';
157	  if (zodType instanceof z.ZodObject) return 'object';
158	  if (zodType instanceof z.ZodEnum) return 'string';
159	  if (zodType instanceof z.ZodLiteral) return typeof zodType._def.values[0];
160	  if (zodType instanceof z.ZodUnion) return 'union';
161	  if (zodType instanceof z.ZodNullable) return zodTypeToJsonType(zodType.unwrap() as z.ZodType);
162	  return 'unknown';
163	}
164	
165	function extractSingleParam(zodType: z.ZodType): ParamInfo {
166	  let isOptional = false;
167	  let inner: z.ZodType = zodType;
168	
169	  if (inner instanceof z.ZodOptional) {
170	    isOptional = true;
171	    inner = inner.unwrap() as z.ZodType;
172	  }
173	  if (inner instanceof z.ZodDefault) {
174	    isOptional = true;
175	    inner = inner.unwrap() as z.ZodType;
176	  }
177	
178	  return {
179	    type: zodTypeToJsonType(inner),
180	    description: inner.description ?? null,
181	    optional: isOptional,
182	  };
183	}
184	
185	function extractParams(schema: z.ZodObject<z.ZodRawShape>): Record<string, ParamInfo> {
186	  const shape = schema.shape;
187	  const result: Record<string, ParamInfo> = {};
188	  for (const [key, zodType] of Object.entries(shape)) {
189	    result[key] = extractSingleParam(zodType as z.ZodType);
190	  }
191	  return result;
192	}
193	
194	// ── Apparatus factory ─────────────────────────────────────────────────
195	
196	export function createOculus(): Plugin {
197	  let serverPort = 7470;
198	  let server: Server | null = null;
199	
200	  const api: OculusApi = {
201	    port(): number {
202	      return serverPort;
203	    },
204	  };
205	
206	  return {
207	    apparatus: {
208	      requires: ['tools'],
209	      consumes: ['pages', 'routes'],
210	      provides: api,
211	
212	      async start(ctx: StartupContext): Promise<void> {
213	        const g = guild();
214	        const oculusConfig: OculusConfig = g.guildConfig().oculus ?? {};
215	        const port = oculusConfig.port ?? 7470;
216	
217	        const app = new Hono();
218	
219	        // Track registered pages and custom route paths
220	        const pages: PageContribution[] = [];
221	        const customRoutePaths = new Set<string>();
222	        const mappedToolRoutes = new Set<string>();
223	
224	        // ── Custom route registration helper ─────────────────────────
225	        function registerCustomRoute(route: RouteContribution, pluginId: string): void {
226	          if (!route.path.startsWith('/api/')) {
227	            console.warn(`[oculus] Custom route "${route.path}" from "${pluginId}" must start with /api/ — skipped`);
228	            return;
229	          }
230	          const method = route.method.toLowerCase() as keyof typeof app;
231	          (app[method] as (path: string, handler: (c: unknown) => unknown) => void)(
232	            route.path,
233	            route.handler as (c: unknown) => unknown,
234	          );
235	          customRoutePaths.add(route.path);
236	        }
237	
238	        // ── Page serving helper ───────────────────────────────────────
239	        function resolveDirForPackage(packageName: string, dir: string): string {
240	          return path.join(g.home, 'node_modules', packageName, dir);
241	        }
242	
243	        function registerPage(page: PageContribution, resolvedDir: string): void {
244	          pages.push({ ...page });
245	
246	          app.get(`/pages/${page.id}/*`, async (c) => {
247	            const requestPath = c.req.path;
248	            const prefix = `/pages/${page.id}/`;
249	            const filePath = requestPath.slice(prefix.length) || 'index.html';
250	
251	            // Prevent directory traversal
252	            if (filePath.includes('..')) {
253	              return c.text('Not found', 404);
254	            }
255	
256	            const absolutePath = path.join(resolvedDir, filePath);
257	
258	            // Ensure file is within resolved dir
259	            if (!absolutePath.startsWith(resolvedDir)) {
260	              return c.text('Not found', 404);
261	            }
262	
263	            try {
264	              const content = fs.readFileSync(absolutePath);
265	              const mimeType = getMimeType(absolutePath);
266	
267	              // Only inject chrome for the root index.html
268	              const isIndexHtml = filePath === 'index.html' || filePath === '';
269	              if (isIndexHtml && mimeType.startsWith('text/html')) {
270	                const html = content.toString('utf-8');
271	                const navHtml = buildNavHtml(pages);
272	                const injected = injectChrome(html, '/static/style.css', navHtml);
273	                return new Response(injected, {
274	                  headers: { 'Content-Type': 'text/html; charset=utf-8' },
275	                });
276	              }
277	
278	              return new Response(content, {
279	                headers: { 'Content-Type': mimeType },
280	              });
281	            } catch {
282	              return c.text('Not found', 404);
283	            }
284	          });
285	        }
286	
287	        // ── Tool route registration helper ───────────────────────────
288	        function registerToolRoute(
289	          toolDef: import('@shardworks/tools-apparatus').ToolDefinition,
290	          instrumentarium: InstrumentariumApi,
291	        ): void {
292	          const routePath = toolNameToRoute(toolDef.name);
293	          const method = permissionToMethod(toolDef.permission);
294	
295	          if (mappedToolRoutes.has(routePath)) return;
296	
297	          if (customRoutePaths.has(routePath)) {
298	            console.warn(
299	              `[oculus] Tool route ${method} ${routePath} conflicts with custom route from plugin — skipped`,
300	            );
301	            return;
302	          }
303	
304	          void instrumentarium; // suppress unused warning
305	
306	          const shape = toolDef.params.shape as Record<string, z.ZodTypeAny>;
307	
308	          if (method === 'GET') {
309	            app.get(routePath, async (c) => {
310	              try {
311	                const rawQuery = c.req.query();
312	                const coerced = coerceParams(shape, rawQuery);
313	                const validated = toolDef.params.parse(coerced);
314	                const result = await toolDef.handler(validated);
315	                return c.json(result);
316	              } catch (err) {
317	                if (err instanceof z.ZodError) {
318	                  return c.json({ error: err.message, details: err.issues }, 400);
319	                }
320	                const message = err instanceof Error ? err.message : String(err);
321	                return c.json({ error: message }, 500);
322	              }
323	            });
324	          } else if (method === 'DELETE') {
325	            app.delete(routePath, async (c) => {
326	              try {
327	                const body = await c.req.json();
328	                const validated = toolDef.params.parse(body);
329	                const result = await toolDef.handler(validated);
330	                return c.json(result);
331	              } catch (err) {
332	                if (err instanceof z.ZodError) {
333	                  return c.json({ error: err.message, details: err.issues }, 400);
334	                }
335	                const message = err instanceof Error ? err.message : String(err);
336	                return c.json({ error: message }, 500);
337	              }
338	            });
339	          } else {
340	            app.post(routePath, async (c) => {
341	              try {
342	                const body = await c.req.json();
343	                const validated = toolDef.params.parse(body);
344	                const result = await toolDef.handler(validated);
345	                return c.json(result);
346	              } catch (err) {
347	                if (err instanceof z.ZodError) {
348	                  return c.json({ error: err.message, details: err.issues }, 400);
349	                }
350	                const message = err instanceof Error ? err.message : String(err);
351	                return c.json({ error: message }, 500);
352	              }
353	            });
354	          }
355	
356	          mappedToolRoutes.add(routePath);
357	        }
358	
359	        // ── Scan contributions from a kit ────────────────────────────
360	        function scanKit(kit: LoadedKit): void {
361	          const oculusKit = kit.kit as OculusKit;
362	
363	          if (oculusKit.routes) {
364	            for (const route of oculusKit.routes) {
365	              registerCustomRoute(route, kit.id);
366	            }
367	          }
368	
369	          if (oculusKit.pages) {
370	            for (const page of oculusKit.pages) {
371	              const resolvedDir = resolveDirForPackage(kit.packageName, page.dir);
372	              registerPage(page, resolvedDir);
373	            }
374	          }
375	        }
376	
377	        function scanApparatus(apparatus: LoadedApparatus): void {
378	          if (!apparatus.apparatus.supportKit) return;
379	          const oculusKit = apparatus.apparatus.supportKit as OculusKit;
380	
381	          if (oculusKit.routes) {
382	            for (const route of oculusKit.routes) {
383	              registerCustomRoute(route, apparatus.id);
384	            }
385	          }
386	
387	          if (oculusKit.pages) {
388	            for (const page of oculusKit.pages) {
389	              const resolvedDir = resolveDirForPackage(apparatus.packageName, page.dir);
390	              registerPage(page, resolvedDir);
391	            }
392	          }
393	        }
394	
395	        // ── Scan existing kits and apparatuses ───────────────────────
396	        for (const kit of g.kits()) {
397	          scanKit(kit);
398	        }
399	        for (const apparatus of g.apparatuses()) {
400	          scanApparatus(apparatus);
401	        }
402	
403	        // ── Register custom routes first ─────────────────────────────
404	        // (already done in scanKit/scanApparatus above)
405	
406	        // ── Register tool routes ─────────────────────────────────────
407	        const instrumentarium = g.apparatus<InstrumentariumApi>('tools');
408	        const allTools = instrumentarium.list();
409	        const patronTools = allTools.filter(
410	          (r) => !r.definition.callableBy || r.definition.callableBy.includes('patron'),
411	        );
412	
413	        for (const resolved of patronTools) {
414	          registerToolRoute(resolved.definition, instrumentarium);
415	        }
416	
417	        // ── GET /api/_tools ──────────────────────────────────────────
418	        app.get('/api/_tools', (c) => {
419	          const tools = instrumentarium.list().filter(
420	            (r) => !r.definition.callableBy || r.definition.callableBy.includes('patron'),
421	          );
422	
423	          const entries = tools.map((r) => ({
424	            name: r.definition.name,
425	            route: toolNameToRoute(r.definition.name),
426	            method: permissionToMethod(r.definition.permission),
427	            description: r.definition.description,
428	            params: extractParams(r.definition.params),
429	          }));
430	
431	          return c.json(entries);
432	        });
433	
434	        // ── Static assets ────────────────────────────────────────────
435	        const staticDir = path.join(import.meta.dirname, 'static');
436	        app.get('/static/*', (c) => {
437	          const requestPath = c.req.path;
438	          const filePath = requestPath.slice('/static/'.length);
439	
440	          if (filePath.includes('..')) {
441	            return c.text('Not found', 404);
442	          }
443	
444	          const absolutePath = path.join(staticDir, filePath);
445	          try {
446	            const content = fs.readFileSync(absolutePath);
447	            const mimeType = getMimeType(absolutePath);
448	            return new Response(content, {
449	              headers: { 'Content-Type': mimeType },
450	            });
451	          } catch {
452	            return c.text('Not found', 404);
453	          }
454	        });
455	
456	        // ── Home page ────────────────────────────────────────────────
457	        app.get('/', (c) => {
458	          const guildName = g.guildConfig().name;
459	          const navHtml = buildNavHtml(pages);
460	
461	          const pageLinks =
462	            pages.length > 0
463	              ? pages
464	                  .map(
465	                    (p) =>
466	                      `<li><a href="/pages/${p.id}/">${p.title}</a></li>`,
467	                  )
468	                  .join('\n        ')
469	              : '<li class="empty-state">No pages registered.</li>';
470	
471	          const html = `<!DOCTYPE html>
472	<html lang="en">
473	<head>
474	  <meta charset="UTF-8">
475	  <meta name="viewport" content="width=device-width, initial-scale=1.0">
476	  <title>${guildName} — Guild Dashboard</title>
477	  <link rel="stylesheet" href="/static/style.css">
478	</head>
479	<body>
480	${navHtml}
481	<main style="padding: 24px;">
482	  <h1>${guildName}</h1>
483	  <div class="card">
484	    <h2>Pages</h2>
485	    <ul>
486	        ${pageLinks}
487	    </ul>
488	  </div>
489	</main>
490	</body>
491	</html>`;
492	
493	          return c.html(html);
494	        });
495	
496	        // ── Late-arriving plugins ─────────────────────────────────────
497	        ctx.on('plugin:initialized', (plugin: unknown) => {
498	          const loaded = plugin as LoadedApparatus | LoadedKit;
499	          if ('apparatus' in loaded) {
500	            scanApparatus(loaded as LoadedApparatus);
501	          } else if ('kit' in loaded) {
502	            scanKit(loaded as LoadedKit);
503	          }
504	
505	          // Check for new patron-callable tools
506	          const currentTools = instrumentarium.list().filter(
507	            (r) => !r.definition.callableBy || r.definition.callableBy.includes('patron'),
508	          );
509	          for (const resolved of currentTools) {
510	            registerToolRoute(resolved.definition, instrumentarium);
511	          }
512	        });
513	
514	        // ── Start HTTP server ─────────────────────────────────────────
515	        await new Promise<void>((resolve, reject) => {
516	          server = serve({ fetch: app.fetch, port }, () => {
517	            serverPort = port;
518	            console.log(`[oculus] Listening on http://localhost:${port}`);
519	            resolve();
520	          }) as Server;
521	          server.on('error', reject);
522	        });
523	      },
524	
525	      async stop(): Promise<void> {
526	        if (server) {
527	          await new Promise<void>((resolve, reject) => {
528	            server!.close((err) => {
529	              if (err) reject(err);
530	              else resolve();
531	            });
532	          });
533	          server = null;
534	        }
535	      },
536	
537	      supportKit: {
538	        tools: [
539	          tool({
540	            name: 'oculus',
541	            description: 'Start the Oculus web dashboard and keep it running',
542	            callableBy: ['patron'],
543	            params: {},
544	            handler: async () => {
545	              const port = api.port();
546	              console.log(`\n  Oculus is running at http://localhost:${port}/\n`);
547	              console.log('  Press Ctrl+C to stop.\n');
548	
549	              // Block until the process is interrupted.
550	              await new Promise<void>((resolve) => {
551	                const onSignal = () => { resolve(); };
552	                process.once('SIGINT', onSignal);
553	                process.once('SIGTERM', onSignal);
554	              });
555	
556	              return 'Oculus stopped.';
557	            },
558	          }),
559	        ],
560	      },
561	    },
562	  };
563	}
