1	/**
2	 * Oculus apparatus — unit tests.
3	 *
4	 * Tests server lifecycle, page serving, chrome injection, tool route mapping,
5	 * custom routes, and the API tool index.
6	 */
7	
8	import fs from 'node:fs';
9	import os from 'node:os';
10	import path from 'node:path';
11	import { describe, it, before, after, afterEach } from 'node:test';
12	import assert from 'node:assert/strict';
13	import { z } from 'zod';
14	
15	import {
16	  setGuild,
17	  clearGuild,
18	  guild,
19	} from '@shardworks/nexus-core';
20	import type {
21	  Guild,
22	  LoadedKit,
23	  LoadedApparatus,
24	  StartupContext,
25	} from '@shardworks/nexus-core';
26	
27	import { tool } from '@shardworks/tools-apparatus';
28	import type { InstrumentariumApi, ResolvedTool } from '@shardworks/tools-apparatus';
29	import type { ToolDefinition } from '@shardworks/tools-apparatus';
30	
31	import { createOculus, toolNameToRoute, permissionToMethod, coerceParams, injectChrome } from './oculus.ts';
32	import type { PageContribution, RouteContribution } from './types.ts';
33	
34	// ── Test helpers ──────────────────────────────────────────────────────
35	
36	let tmpDir: string;
37	
38	function makeTmpDir(): string {
39	  tmpDir = fs.mkdtempSync(path.join(os.tmpdir(), 'oculus-test-'));
40	  return tmpDir;
41	}
42	
43	function cleanupTmpDir(): void {
44	  if (tmpDir) {
45	    try {
46	      fs.rmSync(tmpDir, { recursive: true, force: true });
47	    } catch { /* ignore */ }
48	    tmpDir = '';
49	  }
50	}
51	
52	function makePageDir(parentDir: string, name: string, html: string): string {
53	  const dir = path.join(parentDir, name);
54	  fs.mkdirSync(dir, { recursive: true });
55	  fs.writeFileSync(path.join(dir, 'index.html'), html);
56	  return dir;
57	}
58	
59	function buildTestContext(): {
60	  ctx: StartupContext;
61	  fire: (event: string, ...args: unknown[]) => Promise<void>;
62	} {
63	  const handlers = new Map<string, Array<(...args: unknown[]) => void | Promise<void>>>();
64	
65	  const ctx: StartupContext = {
66	    on(event, handler) {
67	      const list = handlers.get(event) ?? [];
68	      list.push(handler);
69	      handlers.set(event, list);
70	    },
71	  };
72	
73	  async function fire(event: string, ...args: unknown[]): Promise<void> {
74	    for (const h of handlers.get(event) ?? []) {
75	      await h(...args);
76	    }
77	  }
78	
79	  return { ctx, fire };
80	}
81	
82	function mockKit(id: string, tools: unknown[], pages?: PageContribution[], routes?: RouteContribution[]): LoadedKit {
83	  return {
84	    packageName: `@test/${id}`,
85	    id,
86	    version: '0.0.0',
87	    kit: { tools, ...(pages ? { pages } : {}), ...(routes ? { routes } : {}) },
88	  };
89	}
90	
91	/** Build a mock InstrumentariumApi from a flat list of ToolDefinitions. */
92	function createMockInstrumentarium(tools: ToolDefinition[]): InstrumentariumApi {
93	  const resolved: ResolvedTool[] = tools.map((def) => ({ definition: def, pluginId: 'test' }));
94	  return {
95	    list: () => resolved,
96	    find: (name: string) => resolved.find((t) => t.definition.name === name) ?? null,
97	    resolve: () => resolved,
98	  };
99	}
100	
101	function wireGuild(opts: {
102	  home: string;
103	  kits?: LoadedKit[];
104	  apparatuses?: LoadedApparatus[];
105	  instrumentarium: InstrumentariumApi;
106	  guildName?: string;
107	  oculusPort?: number;
108	}): void {
109	  const kits = opts.kits ?? [];
110	  const apparatuses = opts.apparatuses ?? [];
111	  const oculusPort = opts.oculusPort;
112	
113	  const mockGuild: Guild = {
114	    home: opts.home,
115	    apparatus<T>(name: string): T {
116	      if (name === 'tools') return opts.instrumentarium as T;
117	      throw new Error(`apparatus not found: ${name}`);
118	    },
119	    config<T>(_pluginId: string): T {
120	      return {} as T;
121	    },
122	    writeConfig() {},
123	    guildConfig() {
124	      return {
125	        name: opts.guildName ?? 'test-guild',
126	        nexus: '0.0.0',
127	        plugins: [],
128	        ...(oculusPort !== undefined ? { oculus: { port: oculusPort } } : {}),
129	      };
130	    },
131	    kits() { return [...kits]; },
132	    apparatuses() { return [...apparatuses]; },
133	    failedPlugins() { return []; },
134	  };
135	  setGuild(mockGuild);
136	}
137	
138	// ── Unit tests: toolNameToRoute ───────────────────────────────────────
139	
140	describe('toolNameToRoute', () => {
141	  it("'writ-list' → '/api/writ/list'", () => {
142	    assert.equal(toolNameToRoute('writ-list'), '/api/writ/list');
143	  });
144	
145	  it("'commission-post' → '/api/commission/post'", () => {
146	    assert.equal(toolNameToRoute('commission-post'), '/api/commission/post');
147	  });
148	
149	  it("'rig-for-writ' → '/api/rig/for-writ'", () => {
150	    assert.equal(toolNameToRoute('rig-for-writ'), '/api/rig/for-writ');
151	  });
152	
153	  it("'signal' → '/api/signal'", () => {
154	    assert.equal(toolNameToRoute('signal'), '/api/signal');
155	  });
156	
157	  it("'tools-list' → '/api/tools/list'", () => {
158	    assert.equal(toolNameToRoute('tools-list'), '/api/tools/list');
159	  });
160	});
161	
162	// ── Unit tests: permissionToMethod ───────────────────────────────────
163	
164	describe('permissionToMethod', () => {
165	  it("undefined → 'GET'", () => {
166	    assert.equal(permissionToMethod(undefined), 'GET');
167	  });
168	
169	  it("'read' → 'GET'", () => {
170	    assert.equal(permissionToMethod('read'), 'GET');
171	  });
172	
173	  it("'write' → 'POST'", () => {
174	    assert.equal(permissionToMethod('write'), 'POST');
175	  });
176	
177	  it("'admin' → 'POST'", () => {
178	    assert.equal(permissionToMethod('admin'), 'POST');
179	  });
180	
181	  it("'delete' → 'DELETE'", () => {
182	    assert.equal(permissionToMethod('delete'), 'DELETE');
183	  });
184	
185	  it("'clerk:read' → 'GET'", () => {
186	    assert.equal(permissionToMethod('clerk:read'), 'GET');
187	  });
188	
189	  it("'clerk:write' → 'POST'", () => {
190	    assert.equal(permissionToMethod('clerk:write'), 'POST');
191	  });
192	
193	  it("'spider:write' → 'POST'", () => {
194	    assert.equal(permissionToMethod('spider:write'), 'POST');
195	  });
196	
197	  it("'animate' → 'POST' (unknown level)", () => {
198	    assert.equal(permissionToMethod('animate'), 'POST');
199	  });
200	});
201	
202	// ── Unit tests: coerceParams ──────────────────────────────────────────
203	
204	describe('coerceParams', () => {
205	  it('coerces number strings to numbers', () => {
206	    const shape = { limit: z.number() };
207	    const result = coerceParams(shape, { limit: '5' });
208	    assert.equal(result.limit, 5);
209	    assert.equal(typeof result.limit, 'number');
210	  });
211	
212	  it("coerces 'true' to boolean true", () => {
213	    const shape = { verbose: z.boolean() };
214	    const result = coerceParams(shape, { verbose: 'true' });
215	    assert.equal(result.verbose, true);
216	    assert.equal(typeof result.verbose, 'boolean');
217	  });
218	
219	  it("coerces 'false' to boolean false", () => {
220	    const shape = { verbose: z.boolean() };
221	    const result = coerceParams(shape, { verbose: 'false' });
222	    assert.equal(result.verbose, false);
223	  });
224	
225	  it('leaves string values untouched', () => {
226	    const shape = { name: z.string() };
227	    const result = coerceParams(shape, { name: 'hello' });
228	    assert.equal(result.name, 'hello');
229	  });
230	
231	  it('unwraps optional number schema', () => {
232	    const shape = { limit: z.number().optional() };
233	    const result = coerceParams(shape, { limit: '5' });
234	    assert.equal(result.limit, 5);
235	  });
236	
237	  it('unwraps optional boolean schema', () => {
238	    const shape = { flag: z.boolean().optional() };
239	    const result = coerceParams(shape, { flag: 'true' });
240	    assert.equal(result.flag, true);
241	  });
242	});
243	
244	// ── Unit tests: injectChrome ──────────────────────────────────────────
245	
246	describe('injectChrome', () => {
247	  it('injects stylesheet link before </head> and nav after <body>', () => {
248	    const html = '<html><head><title>Test</title></head><body><p>Hi</p></body></html>';
249	    const result = injectChrome(html, '/static/style.css', '<nav>NAV</nav>');
250	    assert.ok(result.includes('<link rel="stylesheet" href="/static/style.css">'));
251	    assert.ok(result.includes('<nav>NAV</nav>'));
252	    // stylesheet should come before </head>
253	    const stylesheetIdx = result.indexOf('<link rel="stylesheet"');
254	    const headCloseIdx = result.indexOf('</head>');
255	    assert.ok(stylesheetIdx < headCloseIdx);
256	    // nav should come after <body>
257	    const navIdx = result.indexOf('<nav>NAV</nav>');
258	    const bodyIdx = result.indexOf('<body>');
259	    assert.ok(navIdx > bodyIdx);
260	  });
261	
262	  it('works case-insensitively and handles body attributes', () => {
263	    const html = '<html><HEAD><TITLE>Test</TITLE></HEAD><BODY class="main"><p>Hi</p></BODY></html>';
264	    const result = injectChrome(html, '/static/style.css', '<nav>NAV</nav>');
265	    assert.ok(result.includes('<link rel="stylesheet"'));
266	    assert.ok(result.includes('<nav>NAV</nav>'));
267	    // nav should appear after the <BODY class="main"> tag
268	    const navIdx = result.indexOf('<nav>NAV</nav>');
269	    const bodyCloseIdx = result.indexOf('<BODY class="main">') + '<BODY class="main">'.length;
270	    assert.ok(navIdx >= bodyCloseIdx);
271	  });
272	
273	  it('returns unmodified when neither <head> nor <body> present', () => {
274	    const html = '<p>No head or body tags</p>';
275	    const result = injectChrome(html, '/static/style.css', '<nav>NAV</nav>');
276	    assert.equal(result, html);
277	  });
278	
279	  it('injects both when head and body are empty', () => {
280	    const html = '<html><head></head><body></body></html>';
281	    const result = injectChrome(html, '/static/style.css', '<nav>NAV</nav>');
282	    assert.ok(result.includes('<link rel="stylesheet"'));
283	    assert.ok(result.includes('<nav>NAV</nav>'));
284	  });
285	});
286	
287	// ── Integration tests: server lifecycle ──────────────────────────────
288	
289	describe('Oculus server lifecycle', () => {
290	  afterEach(() => {
291	    clearGuild();
292	    cleanupTmpDir();
293	  });
294	
295	  it('starts and stops cleanly', async () => {
296	    const home = makeTmpDir();
297	    const instrumentarium = createMockInstrumentarium([]);
298	    const port = 17470 + Math.floor(Math.random() * 100);
299	
300	    wireGuild({ home, kits: [], instrumentarium, oculusPort: port });
301	
302	    const plugin = createOculus();
303	    assert.ok('apparatus' in plugin);
304	
305	    const { ctx } = buildTestContext();
306	
307	    if ('apparatus' in plugin) {
308	      await plugin.apparatus.start(ctx);
309	    }
310	
311	    try {
312	      // Server should be listening
313	      const res = await fetch(`http://localhost:${port}/`);
314	      assert.ok(res.status > 0);
315	
316	      // api.port() should return the port
317	      const api = plugin.apparatus.provides as { port(): number };
318	      assert.equal(api.port(), port);
319	    } finally {
320	      if ('apparatus' in plugin) {
321	        await plugin.apparatus.stop?.();
322	      }
323	    }
324	  });
325	});
326	
327	// ── Integration tests: page serving ──────────────────────────────────
328	
329	describe('Oculus page serving', () => {
330	  let port: number;
331	  let oculusPlugin: ReturnType<typeof createOculus>;
332	  let guildHome: string;
333	
